SELECT mbl.operator_id as oid, mbl.reason AS reason, mbl.id AS id,mbl.operator_nickname AS operName,mbl.type as
type ,mbl.create_time as createTime
FROM md_black_log mbl
WHERE mbl.app_id = #{blackLogParam.appId} AND mbl.user_id = #{blackLogParam.userId}

    AND mbl.create_time > #{blackLogParam.beginTime}


    AND #{blackLogParam.endTime} > mb;.create_time


    AND mbl.type = #{blackLogParam.type}

ORDER BY mbl.create_time DESC
